import{_ as a,o as p,c as t,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"工具异想体（们）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/工具异想体（们）.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/工具异想体（们）.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/工具异想体（们）.md"};function o(d,e,_,l,i,c){return p(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"工具异想体-们",tabindex:"-1"},[b("工具异想体（们） "),r("a",{class:"header-anchor",href:"#工具异想体-们","aria-label":'Permalink to "工具异想体（们）"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),n('<h1 id="工具异想体-们-1" tabindex="-1">工具异想体（们） <a class="header-anchor" href="#工具异想体-们-1" aria-label="Permalink to &quot;工具异想体（们）&quot;">​</a></h1><p>工具异想体（们）</p><p>癫狂研究员的笔记本 D+500</p><p>最后一章仅以一个词作为结尾<br> ————“重生”</p><p>这个异想体是一本老旧的笔记本，里面写满了晦涩难懂的草书。<br> 据说，它的主人曾是一名在实验过程中发疯的研究员。我们目前只破译了一小部分，其内容大多涉及到那名研究员在此地进行的各种实验。<br> 整本笔记本以那名研究员对“非人道实验”的控诉以及他心中无法承受的罪恶感作为开头。但是越往后，其内容就越是被他对研究的狂热和难以理解的词句所取代。<br> .最后一章仅以一个词作为结尾——“重生”。<br> 携带这个异想体的员工能够获得一定的能力提升。但是，倘若在没有满足求知欲的情况下就将其草草归还，那无能的员工就会被它引爆。</p><p>魔幻本质<br> 占据护符位<br> 这个笔记本会为角色提供学识检定上的2DP，意志豁免上+4DP，这是器械加值<br> 当你携带这个异想体经过一次影片时，上述提供的学识检定加值+1DP；意志豁免加值+2DP。<br> 这个笔记本无法取下，如果强行取下，会尽可能多的将生命状态中的生命下降一档：完好→冲击→严重→韧性。</p><p>渴望之心<br> D+500</p><p>过度的渴望会使人发狂。</p><p>该异想体是一颗无主的心脏。尽管已经从肉体上摘除，它也从未停止过跳动。<br> 被员工携带时，心脏的跳动频率将会加倍，并能提高携带者的生命值和攻击能力。<br> 过度的渴望会使人发狂。<br> 如果携带者在归还心脏前没有进行过攻击，或是在携带后30秒内就归还的话，他会失去理智并对看到的一切发起攻击。</p><p>魔幻本质<br> 占据护符位<br> 这颗心脏中央长着一块瘤状物，会为携带它的人提供额外的生命力，因此，你获得了快速治疗1【医疗点12】<br> 携带它的时候，心跳的速度会翻倍，因此获得了力量检定上的+3DP，先攻+2<br> 这颗心脏如果被取下，携带者会进入敌我不分的状态，这个是D级的思维控制效果</p><p>巨树汁液<br> D+500<br> 这棵树会夺回本就属于它的东西。</p><p>这个异想体是一种从不知名的巨树中提取的树汁。<br> 据勘探小组报告，巨树周围环绕着绿色的薄雾，薄雾中混杂着未知的生命形态。饮用树汁会给人舒适的饱腹感，并且树汁中含有大量促进伤口愈合的有效成分。<br> 但是，部分员工喝下树汁后觉得恶心难受，随后便发生了爆炸，只留下一些绿色的残渣。<br> 各项实验证明，喝下树汁后发生爆炸的概率会随着摄取量的增加而急剧提高。<br> “许多人都感到好奇，这样的一棵巨树是如何在贫瘠的郊区中成长壮大起来的？其实它的养分来自于那些吸取过它精华的生物，这棵树会夺回本就属于它的东西。”</p><p>你现在可以以一个迅捷动作喝下树汁。<br> 这会让你在这个场景中获得快速医疗2【医疗点24】<br> 同时树汁为你会带来强韧豁免+2<br> 多次饮用不会叠加数值<br> 一天内多次饮用，需要先进行一个d10，如果结果不为8,9,10，则受到一点不可豁免的韧性伤害</p><p>荧光手镯<br> D+500</p><p>这个手镯不会饶恕那些贪婪的鼠辈，<br> 所以它只该被有需要的人佩戴。</p><p>我们在郊区发现了许多无法以常理解释的异想体实体，这个散发出柔和荧光的手镯就是其中之一。<br> 当一名伤者佩戴手镯后，其身上所有的伤口都会毫无痕迹地快速愈合。<br> .但是，在没有任何伤口的情况下佩戴手镯，是一种非常贪婪的行为。<br> 这个手镯不会饶恕那些贪婪的鼠辈，所以它只该被有需要的人佩戴。</p><p>携带者会获得2点生命值上限<br> 在携带者的生命槽中最好不为完好时，获得快速医疗1【医疗点12】<br> 如果取下该异想体的时候，携带者的生命槽中最好的不为完好，会尽可能多的将生命状态中的生命下降一档：完好→冲击→严重→韧性</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',19)])])}const D=a(s,[["render",o]]);export{f as __pageData,D as default};
